<script setup lang="ts">/* VideoMotionNode — 视频运镜组合器 */import { computed } from 'vue';import { Handle, Position } from '@vue-flow/core';import { useCanvasStore } from '@/stores/canvasStore'
const p=defineProps<{id:string;data:any;selected?:boolean}>();const cs=useCanvasStore();const d=computed(()=>p.data||{})
function patch(k:string,v:string){cs.updateNodeData(p.id,{[k]:v})}
function run(){const parts=[d.value.scene,d.value.action,d.value.path,d.value.rhythm,d.value.stability,d.value.subject].filter(Boolean);cs.updateNodeData(p.id,{outputPrompt:parts.join('，'),status:'success',progress:100})}</script>
<template><div class="x" :class="{sel:selected}" :style="{borderColor:selected?'#ec4899':'var(--border)'}"><div class="xh"><div class="xi" style="background:rgba(236,72,153,.18);color:#f9a8d4"><span class="mso" style="font-size:13px">videocam</span></div><div class="xl">运镜</div><button class="xr" @pointerdown.stop @click.stop="run"><span class="mso">auto_awesome</span></button></div><div class="xb" @mousedown.stop><select class="xi2" @change="patch('scene',($event.target as any).value)"><option value="">场景</option><option value="indoor">室内</option><option value="outdoor">室外</option><option value="studio">影棚</option></select><select class="xi2" @change="patch('action',($event.target as any).value)"><option value="">动作</option><option value="pan">横摇</option><option value="tilt">俯仰</option><option value="dolly">推拉</option><option value="track">跟拍</option></select><select class="xi2" @change="patch('path',($event.target as any).value)"><option value="">路径</option><option value="linear">直线</option><option value="curve">曲线</option><option value="orbit">环绕</option></select><div v-if="data.outputPrompt" class="xo">{{data.outputPrompt}}</div></div><Handle type="source" :position="Position.Right" :style="{background:'#ec4899',width:10,height:10,border:'none'}"/></div></template>
<style scoped>.x{width:280px;border:2px solid var(--border);border-radius:12px;background:var(--paper);box-shadow:var(--jc-shadow-sm);color:var(--ink1)}.x.sel{border-color:#ec4899}.xh{display:flex;align-items:center;gap:8px;padding:8px 12px;border-bottom:1px solid var(--border2)}.xi{width:24px;height:24px;border-radius:6px;display:flex;align-items:center;justify-content:center}.xl{flex:1;font-size:13px;font-weight:600}.xr{width:26px;height:26px;border:1px solid var(--border);border-radius:6px;background:var(--surface);color:var(--ink2);cursor:pointer;display:flex;align-items:center;justify-content:center}.xb{padding:10px;display:flex;flex-direction:column;gap:6px}.xi2{width:100%;border:1px solid var(--border);border-radius:6px;background:var(--surface);color:var(--ink1);padding:5px 8px;font-size:11px;outline:none;font:inherit}.xo{max-height:100px;overflow:auto;white-space:pre-wrap;padding:6px;border-radius:4px;background:var(--surface);font-size:11px;word-break:break-all}</style>
